// Edit this pool freely — one is picked at random per run.
const ideas = [
  'A vampire detective investigates a murder at a midnight concert',
  'A lighthouse keeper discovers the fog is alive and remembers names',
  'An undertaker receives a coffin that arrives one day before each death',
  'A jazz pianist sells half his shadow to play one perfect song',
  'A night-shift radio host realises every caller died years ago',
  'A grave robber finds his own name on tomorrow\'s headstone',
  'A subway line appears on the map only at 3:33 am',
  'A painter\'s portraits age while the subjects stay young',
];

const style = 'dylan-dog';
const idea = ideas[Math.floor(Math.random() * ideas.length)];

// Shell-escape for the Execute Command node.
const sh = (s) => `'${s.replace(/'/g, `'\\''`)}'`;
const projectDir = '/Users/florianzimmermann/Development/Claude/ComicGenerator';
const command = `bash ${projectDir}/scripts/n8n_generate.sh ${sh(idea)} ${sh(style)}`;

return [{ json: { idea, style, command } }];
